rawOutputs.script:
{
  "items": [
    {
      "panel_index": 1,
      "ai_view": "Một người đàn ông đứng trầm mặc, ngắm nhìn một cảnh quan rộng lớn dưới bầu trời đang dần tối sầm.",
      "voiceover_text": "Bầu trời tối sầm xuống. Một sự tĩnh lặng đáng sợ bắt đầu."
    },
    {
      "panel_index": 2,
      "ai_view": "Một người đứng trước một cánh cửa gỗ cũ kỹ. Cánh cửa từ từ mở ra, hé lộ một khoảng tối bên trong.",
      "voiceover_text": "Cửa mở ra... Một bí ẩn đang chờ đợi."
    },
    {
      "panel_index": 3,
      "ai_view": "Người đó tiếp tục quan sát, nhưng lần này, một bóng hình mờ ảo xuất hiện phía sau cánh cửa.",
      "voiceover_text": "Một bóng hình... Sự nguy hiểm đang đến gần."
    },
    {
      "panel_index": 4,
      "ai_view": "Người đó vẫn đứng yên, nhìn ra xa, không có bất kỳ thay đổi nào trong khung cảnh.",
      "voiceover_text": "Không có gì xảy ra. Chỉ có sự chờ đợi."
    },
    {
      "panel_index": 5,
      "ai_view": "Một người đứng trước một cửa hàng nhỏ, vẻ mặt bình tĩnh, nhưng ánh mắt vẫn đầy tò mò.",
      "voiceover_text": "Tiếp theo... Một bước đi quan trọng."
    },
